namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly string[] _templates =
    [
        "New comment on your pull request",
        "Deployment to production succeeded",
        "Build failed for branch main",
        "You were mentioned in issue #42",
        "Security alert: dependency update available",
        "New team member joined the project",
        "Scheduled maintenance window approaching",
        "Your report is ready for download",
    ];

    /// <summary>
    /// Returns a batch of initial notifications (simulates a DB query).
    /// </summary>
    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        var notifications = new List<Notification>();
        for (var i = 0; i < 3; i++)
        {
            notifications.Add(CreateNotification());
        }
        return Task.FromResult(notifications);
    }

    /// <summary>
    /// Simulates checking for new notifications.
    /// ~40 % chance a new notification arrives each poll cycle.
    /// </summary>
    public Task<Notification?> CheckForNewNotificationAsync()
    {
        Notification? result = Random.Shared.Next(100) < 40
            ? CreateNotification()
            : null;
        return Task.FromResult(result);
    }

    private Notification CreateNotification()
    {
        var id = Interlocked.Increment(ref _nextId);
        var message = _templates[Random.Shared.Next(_templates.Length)];
        return new Notification(id, message, DateTime.UtcNow);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorNotifications.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (_notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
    }
</h1>

@if (_notifications is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (_notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@if (_isPolling)
{
    <p class="mt-3 text-success"><small>🟢 Live — polling for new notifications…</small></p>
}

@code {
    private List<Notification>? _notifications;
    private CancellationTokenSource? _cts;
    private bool _isPolling;

    // Runs during SSR *and* when the component re-initializes on the
    // interactive circuit. Because we persist _notifications via the
    // same component instance Blazor re-uses, OnInitializedAsync only
    // fires once — during SSR — so the data is fetched exactly once.
    protected override async Task OnInitializedAsync()
    {
        _notifications = await NotificationSvc.GetInitialNotificationsAsync();
    }

    // Only called once the component is truly interactive in the browser.
    // firstRender == true guarantees we start the loop exactly once.
    protected override Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
        return Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        _isPolling = true;
        await InvokeAsync(StateHasChanged);

        try
        {
            using var timer = new PeriodicTimer(TimeSpan.FromSeconds(5));
            while (await timer.WaitForNextTickAsync(ct))
            {
                var newNotification = await NotificationSvc.CheckForNewNotificationAsync();
                if (newNotification is not null)
                {
                    _notifications?.Insert(0, newNotification);
                    await InvokeAsync(StateHasChanged);
                }
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / navigation away — exit cleanly.
        }
        finally
        {
            _isPolling = false;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

