namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly string[] _templates =
    [
        "New comment on your pull request",
        "Deployment to production succeeded",
        "Build failed for branch main",
        "You were mentioned in issue #42",
        "Security alert: dependency update available",
        "New team member joined the project",
        "Scheduled maintenance window approaching",
        "Your report is ready for download",
    ];

    /// <summary>
    /// Returns a batch of initial notifications (simulates a DB query).
    /// </summary>
    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        var notifications = new List<Notification>();
        for (var i = 0; i < 3; i++)
        {
            notifications.Add(CreateNotification());
        }
        return Task.FromResult(notifications);
    }

    /// <summary>
    /// Simulates checking for new notifications.
    /// ~40 % chance a new notification arrives each poll cycle.
    /// </summary>
    public Task<Notification?> CheckForNewNotificationAsync()
    {
        Notification? result = Random.Shared.Next(100) < 40
            ? CreateNotification()
            : null;
        return Task.FromResult(result);
    }

    private Notification CreateNotification()
    {
        var id = Interlocked.Increment(ref _nextId);
        var message = _templates[Random.Shared.Next(_templates.Length)];
        return new Notification(id, message, DateTime.UtcNow);
    }
}

